const body = $json.body || $json;
const rule = body.rule || {};
const agent = body.agent || {};
const now = new Date().toISOString();

return [{
  json: {
    alert_id: body.id || `alert-${Date.now()}`,
    rule_id: String(rule.id || 'unknown'),
    rule_level: rule.level || 0,
    rule_description: rule.description || 'No description',
    agent_name: agent.name || 'unknown',
    timestamp: body.timestamp || now,
    full_log: body.full_log || 'N/A',
    location: body.location || 'N/A',
    decoder: body.decoder ? body.decoder.name : 'N/A',
    rule_groups: rule.groups ? rule.groups.join(', ') : 'N/A',
    alert_json: JSON.stringify(body),
    processed: false,
    received_at: now
  }
}];

const alerts = $input.all().map(item => item.json);

const alertSummaries = alerts.map((a, i) => {
  return `### Alert ${i + 1}
- **Alert ID**: ${a.alert_id}
- **Rule ID**: ${a.rule_id} (Level ${a.rule_level})
- **Description**: ${a.rule_description}
- **Agent**: ${a.agent_name}
- **Timestamp**: ${a.timestamp}
- **Location**: ${a.location}
- **Decoder**: ${a.decoder}
- **Groups**: ${a.rule_groups}
- **Log**: ${a.full_log}`;
}).join('\n\n');

const prompt = `You are a senior cybersecurity analyst reviewing Wazuh SIEM alerts from a homelab environment. The homelab runs on a single Ubuntu server ("my-server") with Docker containers for various services.

Analyze the following ${alerts.length} alert(s) collected in the last hour. For each alert, provide:
1. **Severity Assessment** (Critical / High / Medium / Low / Informational)
2. **MITRE ATT&CK Mapping** (technique ID and name if applicable)
3. **Analysis** (what happened, is it expected in a homelab?)
4. **Recommended Action** (investigate, monitor, or safe to ignore)

After individual assessments, provide:
- **Executive Summary**: 2-3 sentence overview
- **Overall Threat Level**: Critical / High / Medium / Low / None
- **Top Priority Actions**: Numbered list of what to do first

IMPORTANT: Be practical. This is a homelab, not an enterprise. Flag truly suspicious activity but don't over-alarm on routine system events.

Return your response as valid JSON with this structure:
{
  "executive_summary": "string",
  "overall_threat_level": "string",
  "priority_actions": ["string"],
  "alerts": [
    {
      "alert_id": "string",
      "severity": "string",
      "mitre_attack": "string or null",
      "analysis": "string",
      "recommended_action": "string"
    }
  ]
}

---

${alertSummaries}`;

const alertIds = alerts.map(a => a.id || a.alert_id);
const alertCount = alerts.length;
const maxLevel = Math.max(...alerts.map(a => a.rule_level || 0));

return [{
  json: {
    chatInput: prompt,
    alertIds: alertIds,
    alertCount: alertCount,
    maxLevel: maxLevel,
    rawAlerts: alerts
  }
}];

const input = $input.first().json;
const prevData = $('Prepare Gemini Prompt').first().json;

let rawText = input.text || input.output || JSON.stringify(input);

let analysis;
try {
  const jsonMatch = rawText.match(/```(?:json)?\s*([\s\S]*?)```/);
  const jsonStr = jsonMatch ? jsonMatch[1].trim() : rawText.trim();
  analysis = JSON.parse(jsonStr);
} catch (e) {
  analysis = {
    executive_summary: 'AI analysis returned non-JSON response. Raw output included below.',
    overall_threat_level: 'Unknown',
    priority_actions: ['Review raw AI output manually'],
    alerts: [],
    raw_output: rawText
  };
}

return [{
  json: {
    analysis: analysis,
    alertIds: prevData.alertIds,
    alertCount: prevData.alertCount,
    maxLevel: prevData.maxLevel,
    rawAlerts: prevData.rawAlerts
  }
}];

const { analysis, alertCount, maxLevel, rawAlerts } = $input.first().json;
const now = new Date().toISOString().replace('T', ' ').substring(0, 19);

const threatColors = {
  'Critical': '#dc3545', 'High': '#fd7e14', 'Medium': '#ffc107',
  'Low': '#28a745', 'None': '#6c757d', 'Informational': '#17a2b8', 'Unknown': '#6c757d'
};
const threatColor = threatColors[analysis.overall_threat_level] || '#6c757d';

let html = `<!DOCTYPE html>
<html>
<head><meta charset="utf-8"><style>
  body { font-family: -apple-system, BlinkMacSystemFont, 'Segoe UI', Roboto, sans-serif; margin: 0; padding: 20px; background: #f5f5f5; }
  .container { max-width: 700px; margin: 0 auto; background: #fff; border-radius: 8px; overflow: hidden; box-shadow: 0 2px 8px rgba(0,0,0,0.1); }
  .header { background: ${threatColor}; color: #fff; padding: 20px 24px; }
  .header h1 { margin: 0; font-size: 20px; }
  .header .meta { opacity: 0.9; font-size: 13px; margin-top: 4px; }
  .body { padding: 24px; }
  .summary { background: #f8f9fa; border-left: 4px solid ${threatColor}; padding: 12px 16px; margin-bottom: 20px; border-radius: 0 4px 4px 0; }
  .alert-card { border: 1px solid #e0e0e0; border-radius: 6px; padding: 14px; margin-bottom: 12px; }
  .alert-card h3 { margin: 0 0 8px 0; font-size: 14px; }
  .severity { display: inline-block; padding: 2px 8px; border-radius: 12px; font-size: 11px; font-weight: 600; color: #fff; }
  .severity-critical { background: #dc3545; } .severity-high { background: #fd7e14; }
  .severity-medium { background: #ffc107; color: #333; } .severity-low { background: #28a745; }
  .severity-informational { background: #17a2b8; }
  .actions { background: #fff3cd; border: 1px solid #ffc107; border-radius: 6px; padding: 14px; margin-top: 16px; }
  .actions h3 { margin: 0 0 8px 0; font-size: 14px; color: #856404; }
  .actions ol { margin: 0; padding-left: 20px; }
  .footer { padding: 16px 24px; background: #f8f9fa; font-size: 12px; color: #666; border-top: 1px solid #e0e0e0; }
</style></head>
<body>
<div class="container">
  <div class="header">
    <h1>Wazuh Security Digest</h1>
    <div class="meta">${alertCount} alert(s) | Max Level: ${maxLevel} | ${now} UTC</div>
  </div>
  <div class="body">
    <div class="summary">
      <strong>Threat Level: ${analysis.overall_threat_level}</strong><br/>
      ${analysis.executive_summary}
    </div>`;

if (analysis.alerts && analysis.alerts.length > 0) {
  analysis.alerts.forEach((a, i) => {
    const sevClass = 'severity-' + (a.severity || 'low').toLowerCase();
    const matchingRaw = rawAlerts[i] || {};
    html += `\n    <div class="alert-card">\n      <h3>${matchingRaw.rule_description || a.alert_id || 'Alert ' + (i+1)} <span class="severity ${sevClass}">${a.severity}</span></h3>\n      <p style="margin:4px 0;font-size:13px;"><strong>Rule:</strong> ${matchingRaw.rule_id || 'N/A'} | <strong>Agent:</strong> ${matchingRaw.agent_name || 'N/A'} | <strong>MITRE:</strong> ${a.mitre_attack || 'N/A'}</p>\n      <p style="margin:4px 0;font-size:13px;">${a.analysis}</p>\n      <p style="margin:4px 0;font-size:12px;color:#666;"><strong>Action:</strong> ${a.recommended_action}</p>\n    </div>`;
  });
}

if (analysis.priority_actions && analysis.priority_actions.length > 0) {
  html += `\n    <div class="actions">\n      <h3>Priority Actions</h3>\n      <ol>`;
  analysis.priority_actions.forEach(action => {
    html += `<li style="margin-bottom:4px;font-size:13px;">${action}</li>`;
  });
  html += `</ol></div>`;
}

html += `\n  </div>\n  <div class="footer">\n    Generated by n8n Wazuh Alert Pipeline | Homelab Security Monitoring\n  </div>\n</div>\n</body></html>`;

let md = `# Wazuh Security Digest\n`;
md += `**Date:** ${now} UTC\n`;
md += `**Alerts:** ${alertCount} | **Max Level:** ${maxLevel} | **Threat Level:** ${analysis.overall_threat_level}\n\n`;
md += `## Executive Summary\n${analysis.executive_summary}\n\n`;

if (analysis.alerts && analysis.alerts.length > 0) {
  md += `## Alert Details\n\n`;
  analysis.alerts.forEach((a, i) => {
    const matchingRaw = rawAlerts[i] || {};
    md += `### ${i+1}. ${matchingRaw.rule_description || a.alert_id || 'Alert'}\n`;
    md += `- **Severity:** ${a.severity}\n`;
    md += `- **Rule ID:** ${matchingRaw.rule_id || 'N/A'} (Level ${matchingRaw.rule_level || 'N/A'})\n`;
    md += `- **Agent:** ${matchingRaw.agent_name || 'N/A'}\n`;
    md += `- **MITRE ATT&CK:** ${a.mitre_attack || 'N/A'}\n`;
    md += `- **Timestamp:** ${matchingRaw.timestamp || 'N/A'}\n`;
    md += `- **Analysis:** ${a.analysis}\n`;
    md += `- **Action:** ${a.recommended_action}\n`;
    md += `- **Log:** \`${matchingRaw.full_log || 'N/A'}\`\n\n`;
  });
}

if (analysis.priority_actions && analysis.priority_actions.length > 0) {
  md += `## Priority Actions\n`;
  analysis.priority_actions.forEach((action, i) => { md += `${i+1}. ${action}\n`; });
  md += `\n`;
}
md += `---\n*Generated by n8n Wazuh Alert Pipeline*\n`;

const threatEmoji = { 'Critical': '\uD83D\uDD34', 'High': '\uD83D\uDFE0', 'Medium': '\uD83D\uDFE1', 'Low': '\uD83D\uDFE2', 'None': '\u26AA', 'Unknown': '\u2753' };
const emoji = threatEmoji[analysis.overall_threat_level] || '\uD83D\uDEE1\uFE0F';
let gotifyMsg = `${emoji} ${analysis.overall_threat_level}: ${alertCount} alert(s)\n\n${analysis.executive_summary}`;
if (analysis.priority_actions && analysis.priority_actions.length > 0) {
  gotifyMsg += `\n\nActions:\n` + analysis.priority_actions.map((a, i) => `${i+1}. ${a}`).join('\n');
}

const gotifyPriority = { 'Critical': 9, 'High': 7, 'Medium': 5, 'Low': 3, 'None': 1, 'Unknown': 5 };
const mdBuffer = Buffer.from(md, 'utf-8');

return [{
  json: {
    subject: `${emoji} Wazuh Digest: ${analysis.overall_threat_level} - ${alertCount} alert(s)`,
    htmlBody: html,
    gotifyTitle: `Wazuh: ${analysis.overall_threat_level} (${alertCount} alerts)`,
    gotifyMessage: gotifyMsg,
    gotifyPriority: gotifyPriority[analysis.overall_threat_level] || 5,
    alertCount: alertCount,
    analysis: analysis
  },
  binary: {
    report: {
      data: mdBuffer.toString('base64'),
      mimeType: 'text/markdown',
      fileName: `wazuh-digest-${now.replace(/[: ]/g, '-')}.md`,
      fileExtension: 'md'
    }
  }
}];

const alertRows = $('Get Unprocessed Alerts').all();

return alertRows.map(row => ({
  json: {
    id: row.json.id,
    processed: true
  }
}));
